            shootInterval: 50, // frames
            moveDirection: 1, // 1 for right, -1 for left
            lastHit: 0,
            invulnerabilityDuration: 10 // frames (visual only for hit feedback)
        };

        // Game Objects
        const bullets = [];
        const enemies = [];
        const particles = [];

        // Input handling
        const keys = {
            ArrowUp: false, w: false,
            ArrowDown: false, s: false,
            ArrowLeft: false, a: false,
            ArrowRight: false, d: false,
            Space: false
        };

        document.addEventListener('keydown', (e) => {
            if (e.code in keys) keys[e.code] = true;
            if (e.key.toLowerCase() in keys) keys[e.key.toLowerCase()] = true;
        });

        document.addEventListener('keyup', (e) => {
            if (e.code in keys) keys[e.code] = false;
            if (e.key.toLowerCase() in keys) keys[e.key.toLowerCase()] = false;
        });

        function resetGame() {
            player.x = canvas.width / 2 - 20;
            player.y = canvas.height - 70;
            player.health = player.maxHealth;
            player.bullets = [];
            player.shootCooldown = 0;
            player.lastHit = 0;

            boss.x = canvas.width / 2 - 60;
            boss.y = 50;
            boss.health = boss.maxHealth;
            boss.bullets = [];
            boss.shootCooldown = 0;
            boss.lastHit = 0;
            boss.moveDirection = 1;

            bullets.length = 0; // Clear all bullets
            enemies.length = 0; // Clear all enemies
            particles.length = 0; // Clear all particles
            score = 0;

            updateUI();
            gameOverScreen.style.display = 'none';
            startScreen.style.display = 'flex';
        }

        function startGame() {
            gameRunning = true;
            startScreen.style.display = 'none';
            gameLoop();
        }

        function endGame() {
            gameRunning = false;
            cancelAnimationFrame(animationFrameId);
            finalScoreDisplay.textContent = score;
            gameOverScreen.style.display = 'flex';
        }

        startButton.addEventListener('click', startGame);
        restartButton.addEventListener('click', () => {
            resetGame();
            startGame();
        });

        // Game Loop
        function gameLoop() {
            if (!gameRunning) return;

            update();
            draw();

            animationFrameId = requestAnimationFrame(gameLoop);
        }

        // Update Game State
        function update() {
            updatePlayer();
            updateBoss();
            updateBullets();
            updateCollisions();
            updateParticles();
            updateUI();

            if (player.health <= 0) {
                endGame();
            }
            if (boss.health <= 0) {
                // Boss defeated, maybe a victory screen or next level
                score += 1000; // Bonus for defeating boss
                endGame(); // For now, end the game
            }
