                    x: player.x + player.width / 2 - 2.5,
                    y: player.y,
                    width: 5,
                    height: 10,
                    speed: 10,
                    color: 'lime',
                    isPlayerBullet: true
                });
                player.shootCooldown = player.shootInterval;
            }
            if (player.shootCooldown > 0) {
                player.shootCooldown--;
            }

            // Invulnerability
            if (player.lastHit > 0) {
                player.lastHit--;
            }
        }

        function updateBoss() {
            // Movement
            boss.x += boss.speedX * boss.moveDirection;
            if (boss.x <= 0 || boss.x >= canvas.width - boss.width) {
                boss.moveDirection *= -1;
            }

            // Shooting (simple pattern)
            if (boss.shootCooldown === 0) {
                // Shoot three bullets in a spread
                boss.bullets.push({
                    x: boss.x + boss.width / 2 - 2.5,
                    y: boss.y + boss.height,
                    width: 5,
                    height: 10,
                    speed: 5,
                    color: 'orange',
                    isPlayerBullet: false,
                    dx: 0, dy: 1
                });
                boss.bullets.push({
                    x: boss.x + boss.width / 2 - 2.5 - 15,
                    y: boss.y + boss.height,
                    width: 5,
                    height: 10,
                    speed: 5,
                    color: 'orange',
                    isPlayerBullet: false,
                    dx: -0.5, dy: 1
                });
                boss.bullets.push({
                    x: boss.x + boss.width / 2 - 2.5 + 15,
                    y: boss.y + boss.height,
                    width: 5,
                    height: 10,
                    speed: 5,
                    color: 'orange',
                    isPlayerBullet: false,
                    dx: 0.5, dy: 1
                });
                boss.shootCooldown = boss.shootInterval;
            }
            if (boss.shootCooldown > 0) {
                boss.shootCooldown--;
            }

            // Update boss bullets
            for (let i = boss.bullets.length - 1; i >= 0; i--) {
                const bullet = boss.bullets[i];
                bullet.x += bullet.speed * bullet.dx;
                bullet.y += bullet.speed * bullet.dy;

                // Remove if off-screen
                if (bullet.y > canvas.height || bullet.x < -bullet.width || bullet.x > canvas.width) {
                    boss.bullets.splice(i, 1);
                }
            }

            // Invulnerability (visual only for hit feedback)
            if (boss.lastHit > 0) {
                boss.lastHit--;
            }
        }

        function updateBullets() {
            for (let i = bullets.length - 1; i >= 0; i--) {
                const bullet = bullets[i];
                bullet.y -= bullet.speed;

                // Remove if off-screen
                if (bullet.y < 0) {
                    bullets.splice(i, 1);
                }
            }
        }

        function updateCollisions() {
            // Player bullets vs Boss
            for (let i = bullets.length - 1; i >= 0; i--) {
                const bullet = bullets[i];
                if (bullet.isPlayerBullet && checkCollision(bullet, boss)) {
                    if (boss.lastHit === 0) { // Only take damage if not recently hit
                        boss.health -= 10;
                        score += 10;
                        boss.lastHit = boss.invulnerabilityDuration;
                        createParticles(bullet.x, bullet.y, 'white', 5); // Hit effect
                    }
                    bullets.splice(i, 1); // Remove bullet on hit
                    continue;
                }
            }

            // Boss bullets vs Player
            for (let i = boss.bullets.length - 1; i >= 0; i--) {
                const bullet = boss.bullets[i];
                if (!bullet.isPlayerBullet && checkCollision(bullet, player)) {
                    if (player.lastHit === 0) { // Only take damage if not invulnerable
                        player.health -= 20;
                        player.lastHit = player.invulnerabilityDuration;
                        createParticles(bullet.x, bullet.y, 'red', 10); // Hit effect
                    }
                    boss.bullets.splice(i, 1); // Remove bullet on hit
                    continue;
                }
            }
        }

        function updateParticles() {
            for (let i = particles.length - 1; i >= 0; i--) {
                const p = particles[i];
                p.x += p.vx;
                p.y += p.vy;
                p.alpha -= 0.05;
                if (p.alpha <= 0) {
                    particles.splice(i, 1);
                }
            }
        }

        function checkCollision(rect1, rect2) {
            return rect1.x < rect2.x + rect2.width &&
                   rect1.x + rect1.width > rect2.x &&
                   rect1.y < rect2.y + rect2.height &&
                   rect1.y + rect1.height > rect2.y;
        }

        function createParticles(x, y, color, count) {
            for (let i = 0; i < count; i++) {
                particles.push({
                    x: x,
                    y: y,
                    vx: (Math.random() - 0.5) * 3,
                    vy: (Math.random() - 0.5) * 3,
                    radius: Math.random() * 2 + 1,
                    color: color,
                    alpha: 1
                });
            }
        }

        // Draw Game Elements
        function draw() {
            ctx.clearRect(0, 0, canvas.width, canvas.height); // Clear canvas

            drawPlayer();
            drawBoss();
            drawBullets();
            drawParticles();
        }

        function drawPlayer() {
            ctx.save();
            if (player.lastHit > 0 && Math.floor(player.lastHit / 5) % 2 === 0) {
                ctx.globalAlpha = 0.5; // Flash effect when invulnerable
            }
            ctx.fillStyle = player.color;
            ctx.fillRect(player.x, player.y, player.width, player.height);
            ctx.restore();
        }

        function drawBoss() {
            ctx.save();
            if (boss.lastHit > 0 && Math.floor(boss.lastHit / 2) % 2 === 0) {
                ctx.globalAlpha = 0.7; // Flash effect when hit
            }
            ctx.fillStyle = boss.color;
            ctx.fillRect(boss.x, boss.y, boss.width, boss.height);
            ctx.restore();
        }

        function drawBullets() {
            // Player bullets
            for (const bullet of bullets) {
                ctx.fillStyle = bullet.color;
                ctx.fillRect(bullet.x, bullet.y, bullet.width, bullet.height);
            }
            // Boss bullets
            for (const bullet of boss.bullets) {
                ctx.fillStyle = bullet.color;
                ctx.fillRect(bullet.x, bullet.y, bullet.width, bullet.height);
            }
        }

        function drawParticles() {
            for (const p of particles) {
                ctx.save();
                ctx.globalAlpha = p.alpha;
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            }
        }

        function updateUI() {
            scoreDisplay.textContent = score;
            playerHealthDisplay.textContent = player.health;
            bossHealthDisplay.textContent = boss.health > 0 ? boss.health : 'Defeated!';
            // Update health bars if needed, for simplicity using text for now
        }

